import pandas as pd, glob
for name in ['task_assignment','code_review','approval','qa_test','deployment']:
    if name=='task_assignment':
        df=pd.concat([pd.read_csv(f) for f in sorted(glob.glob('/app/task_assignment_*.csv'))])
        start=pd.to_datetime(df['assigned_at'])
        end=pd.to_datetime(df['unassigned_at'])
        dur=(end-start).dt.total_seconds()/3600
        print(name, 'hours mean', round(dur.mean(),2), 'p50', round(dur.median(),2), 'p90', round(dur.quantile(.9),2), 'p99', round(dur.quantile(.99),2), 'max', round(dur.max(),2))
        print(df['assignment_role'].value_counts().head(12).to_string())
    else:
        f=f'/app/{name}_001.csv'
        df=pd.read_csv(f)
        if name=='code_review':
            start,end='requested_at','completed_at'; who='reviewer_id'
        elif name=='approval':
            start,end='requested_at','resolved_at'; who='approver_id'
        elif name=='qa_test':
            print(name, 'unique testers', df['tester_id'].nunique(), 'rows', len(df)); continue
        elif name=='deployment':
            print(name, 'unique approved_by', df['approved_by'].nunique(), 'rows', len(df)); continue
