import pandas as pd, numpy as np
x=pd.read_csv('/tmp/direct_stage_metrics.csv')
role_groups=[]
for role, g in x.groupby('role'):
    g=g.copy()
    for col in ['median_ratio','total_excess_h','overload_signal','stage_rows','meeting_hours','sent_in_hours','impacted_tasks']:
        med=g[col].median(); mad=(g[col]-med).abs().median();
        g[col+'_z']=0 if mad==0 else 0.6745*(g[col]-med)/mad
    g['poor_score']=g['median_ratio_z'].clip(lower=0)+0.5*g['total_excess_h_z'].clip(lower=0)+0.25*g['impacted_tasks_z'].clip(lower=0)
    role_groups.append(g)
allg=pd.concat(role_groups)
for eid in [41,91,100,170,57,315,155,217,29,306,205,298]:
    r=allg[allg.employee_id==eid][['employee_id','role','stage_rows','median_ratio','total_excess_h','impacted_tasks','poor_score']]
    print(r.to_string(index=False))
